9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const countLiveNeighbors = (cell: Cell, alive: Set<string>): number =>
15	  neighborsOf(cell).filter((n) => alive.has(cellKey(n))).length;
16	
