21	  const alive = new Set(cells.map(cellKey));
22	  const candidates = uniqueCells(cells.flatMap((c) => [c, ...neighborsOf(c)]));
23	  return candidates.filter((c) =>
24	    willLive(alive.has(cellKey(c)), countLiveNeighbors(c, alive))
25	  );
26	}
